// ============================================
// CARD COMPONENT
// ============================================

export interface CardProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof cardVariants> {
  /**
   * Render as a different element (e.g., 'article', 'section')
   */
  as?: React.ElementType;
}

/**
 * Card Component
 *
 * A versatile container component for grouping related content.
 * Supports multiple variants, sizes, and can be composed with
 * CardHeader, CardTitle, CardDescription, CardContent, and CardFooter.
 *
 * @example
 * // Basic usage
 * <Card>
 *   <CardHeader>
 *     <CardTitle>Title</CardTitle>
 *     <CardDescription>Description</CardDescription>
 *   </CardHeader>
 *   <CardContent>Content here</CardContent>
 *   <CardFooter>Footer actions</CardFooter>
 * </Card>
 *
 * @example
 * // Interactive card
 * <Card variant="interactive" onClick={handleClick}>
 *   <CardContent>Click me!</CardContent>
 * </Card>
 */
const Card = React.forwardRef<HTMLDivElement, CardProps>(
  ({ className, variant, size, fullWidth, as: Component = "div", ...props }, ref) => {
    return (
      <Component
        ref={ref}
        className={cn(cardVariants({ variant, size, fullWidth }), className)}
        {...props}
      />
    );
  }
);
Card.displayName = "Card";

