// ============================================
// CARD SKELETON COMPONENT
// ============================================

export interface CardSkeletonProps extends React.HTMLAttributes<HTMLDivElement> {
  /**
   * Show image skeleton
   */
  hasImage?: boolean;

  /**
   * Number of content lines
   */
  lines?: number;

  /**
   * Show footer skeleton
   */
  hasFooter?: boolean;
}

/**
 * CardSkeleton Component
 *
 * Loading placeholder for cards.
 */
const CardSkeleton = React.forwardRef<HTMLDivElement, CardSkeletonProps>(
  ({ className, hasImage = true, lines = 3, hasFooter = true, ...props }, ref) => (
    <Card ref={ref} className={cn("overflow-hidden", className)} {...props}>
      {/* Image skeleton */}
      {hasImage && (
        <div className="aspect-video w-full animate-pulse bg-muted" />
      )}

      {/* Header skeleton */}
      <CardHeader>
        <div className="h-5 w-3/4 animate-pulse rounded bg-muted" />
        <div className="h-4 w-1/2 animate-pulse rounded bg-muted" />
      </CardHeader>

      {/* Content skeleton */}
      <CardContent>
        <div className="space-y-2">
          {Array.from({ length: lines }).map((_, i) => (
            <div
              key={i}
              className={cn(
                "h-4 animate-pulse rounded bg-muted",
                i === lines - 1 && "w-4/5"
              )}
            />
          ))}
        </div>
      </CardContent>

      {/* Footer skeleton */}
      {hasFooter && (
        <CardFooter>
          <div className="h-9 w-24 animate-pulse rounded bg-muted" />
        </CardFooter>
      )}
    </Card>
  )
);
CardSkeleton.displayName = "CardSkeleton";

// ============================================
// CARD GROUP COMPONENT
// ============================================

export interface CardGroupProps extends React.HTMLAttributes<HTMLDivElement> {
  /**
   * Layout direction
   */
  direction?: "row" | "column";

  /**
   * Gap between cards
   */
  gap?: "none" | "sm" | "md" | "lg";

  /**
   * Number of columns (for grid layout)
   */
  columns?: 1 | 2 | 3 | 4;
}

/**
 * CardGroup Component
 *
 * Container for grouping multiple cards with consistent spacing.
 */
const CardGroup = React.forwardRef<HTMLDivElement, CardGroupProps>(
  (
    { className, direction = "row", gap = "md", columns, children, ...props },
    ref
  ) => {
    const gapClasses = {
      none: "gap-0",
      sm: "gap-2",
      md: "gap-4",
      lg: "gap-6",
    };

    const columnClasses = {
      1: "grid-cols-1",
      2: "grid-cols-1 sm:grid-cols-2",
      3: "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3",
      4: "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4",
    };

    // Use grid if columns specified, otherwise flex
    if (columns) {
      return (
        <div
          ref={ref}
          className={cn("grid", columnClasses[columns], gapClasses[gap], className)}
          {...props}
        >
          {children}
        </div>
      );
    }

    return (
      <div
        ref={ref}
        className={cn(
          "flex",
          direction === "row" ? "flex-row flex-wrap" : "flex-col",
          gapClasses[gap],
          className
        )}
        {...props}
      >
        {children}
      </div>
    );
  }
);
CardGroup.displayName = "CardGroup";

